// specify the entire scene's coordinate system (comment all out for default right-handed, z-up)
#define ST_COORD_SYS_RHCS_ZUP
//#define ST_COORD_SYS_RHCS_YUP
//#define ST_COORD_SYS_LHCS_ZUP
//#define ST_COORD_SYS_LHCS_YUP

// used in diagnostics to ensure that not floating point exceptions are being generated by the SpeedTree SDK
//#if defined(_WIN32) && !defined(NDEBUG)
//  #define ST_FLOATING_POINT_EXCEPTIONS    (EM_OVERFLOW | EM_ZERODIVIDE | EM_DENORMAL/* | EM_INVALID | EM_UNDERFLOW*/)
//#endif

