///////////////////////////////////////////////////////////////////////
//  CMyApplication::ReportResourceUsage

void CMyApplication::ReportResourceUsage(void)
{
    const CCore::SResourceSummary& sSummary = CCore::GetSdkResourceUsage( );

    Report("\t     Resource  Usage (KB) Peak (KB)  Qty   Peak\n");
    Report("\t---------------------------------------------------\n");
    Report("\t          heap %8.1f  (%8.1f)  %d (%d)\n",
        sSummary.m_sHeap.m_siCurrentUsage / 1024.0f, sSummary.m_sHeap.m_siPeakUsage / 1024.0f,
        st_uint32(sSummary.m_sHeap.m_siCurrentQuantity), st_uint32(sSummary.m_sHeap.m_siPeakQuantity));

    const char* c_pGfxNames[GFX_RESOURCE_COUNT] =
    {
        "vertex buffers",
        "index buffers",
        "vertex shaders",
        "pixel shaders",
        "textures",
        "other"
    };

    for (st_int32 i = GFX_RESOURCE_VERTEX_BUFFER; i < GFX_RESOURCE_COUNT; ++i)
    {
        // for now, skip vertex & pixel shaders since we don't have a good way to measure their 
        // footprint across all platforms
        if (i != GFX_RESOURCE_VERTEX_SHADER && i != GFX_RESOURCE_PIXEL_SHADER)
        {
            Report("\t%14s %8.1f  (%8.1f)  %4d (%4d)",
                    c_pGfxNames[i],
                    sSummary.m_asGfxResources[i].m_siCurrentUsage / 1024.0f, sSummary.m_asGfxResources[i].m_siPeakUsage / 1024.0f,
                    st_uint32(sSummary.m_asGfxResources[i].m_siCurrentQuantity), st_uint32(sSummary.m_asGfxResources[i].m_siPeakQuantity));
        }
    }
    Report("\n");
}


///////////////////////////////////////////////////////////////////////
//  CMyApplication::ConstrainCamera

Vec3 CMyApplication::ConstrainCameraPos(const Vec3& vInputCameraPos) const
{
    // convert camera pos to std coord system
    Vec3 vConstrainedCameraPos = CCoordSys::ConvertToStd(vInputCameraPos);

    // clamp to tiles
    if (m_cConfigFile.m_sTerrain.m_nTiles > 0)
    {
        if (vConstrainedCameraPos.x < 0.0f)
            vConstrainedCameraPos.x = 0.0f;
        if (vConstrainedCameraPos.y < 0.0f)
            vConstrainedCameraPos.y = 0.0f;
        if (vConstrainedCameraPos.x > m_cConfigFile.m_sTerrain.m_vHeightMapSize.x * st_float32(m_cConfigFile.m_sTerrain.m_nTiles))
            vConstrainedCameraPos.x = m_cConfigFile.m_sTerrain.m_vHeightMapSize.x * st_float32(m_cConfigFile.m_sTerrain.m_nTiles);
        if (vConstrainedCameraPos.y > m_cConfigFile.m_sTerrain.m_vHeightMapSize.y * st_float32(m_cConfigFile.m_sTerrain.m_nTiles))
            vConstrainedCameraPos.y = m_cConfigFile.m_sTerrain.m_vHeightMapSize.y * st_float32(m_cConfigFile.m_sTerrain.m_nTiles);
    }

    if (m_bFollowTerrain || m_bHandleCollision)
    {
        const st_float32 c_fSmoothingDistance = 3.0f;
        st_float32 fTerrainHeight = m_cTerrain.GetSmoothHeightFromXY(vConstrainedCameraPos.x, vConstrainedCameraPos.y, c_fSmoothingDistance * m_cConfigFile.m_sNavigation.m_fFollowHeight) + m_cConfigFile.m_sNavigation.m_fFollowHeight;

        if (m_bFollowTerrain)
            vConstrainedCameraPos.Set(vConstrainedCameraPos.x, vConstrainedCameraPos.y, fTerrainHeight);
        else if (m_bHandleCollision)
            vConstrainedCameraPos.z = st_max(vConstrainedCameraPos.z, fTerrainHeight);
    }

    vConstrainedCameraPos = CCoordSys::ConvertFromStd(vConstrainedCameraPos);

    if (m_bHandleCollision)
    {
        const st_int32 c_nMaxNumTestTrees = 5;
        (void) m_cForest.CollisionAdjust(vConstrainedCameraPos, m_cVisibleTreesFromCamera, c_nMaxNumTestTrees);
    }

    return vConstrainedCameraPos;
}


