///////////////////////////////////////////////////////////////////////
//  CMyApplication::UpdateHandTune

void CMyApplication::UpdateHandTunedValues(const st_float32 afValues[4])
{
    printf("%s = %g, %s = %g, %s = %g, %s = %g\n",
        m_cConfigFile.m_sDemo.m_strHandTunedName0.c_str( ), afValues[0], 
        m_cConfigFile.m_sDemo.m_strHandTunedName1.c_str( ), afValues[1], 
        m_cConfigFile.m_sDemo.m_strHandTunedName2.c_str( ), afValues[2], 
        m_cConfigFile.m_sDemo.m_strHandTunedName3.c_str( ), afValues[3]);

    m_cForest.GetFrameConstantBuffer( ).u_vHandTunedParams = Vec4(afValues);
}


///////////////////////////////////////////////////////////////////////
//  CMyApplication::ToggleFeature

void CMyApplication::ToggleFeature(EToggleFeature eFeature)
{
    switch (eFeature)
    {
    case TOGGLE_3D_TREE_VISIBILITY:
        m_bRender3dTrees = !m_bRender3dTrees;
        break;
    case TOGGLE_BILLBOARD_VISIBILITY:
        m_bRenderBillboards = !m_bRenderBillboards; 
        break;
    case TOGGLE_BLOOM_DISPLAY_MODE:
        if (++m_nBloomDisplayMode == st_int32(BLOOM_DISPLAY_MODE_COUNT))
            m_nBloomDisplayMode = BLOOM_DISPLAY_MODE_FULL;
        break;
    case TOGGLE_COLLISION:
        m_bHandleCollision = !m_bHandleCollision;
        break;
    case TOGGLE_DEPTH_BLUR:
        m_bDepthBlur = !m_bDepthBlur;
        break;
    case TOGGLE_GRASS_VISIBILITY:
        m_bRenderGrass = !m_bRenderGrass; 
        break;
    case TOGGLE_OVERLAY_VISIBILITY:
        m_bRenderOverlays = !m_bRenderOverlays;
        break;
    case TOGGLE_SKY_VISIBILITY:
        m_cSky.SetActive(!m_cSky.IsActive( ));
        break;
    case TOGGLE_TERRAIN_FOLLOWING:
        m_bFollowTerrain = !m_bFollowTerrain; 
        break;
    case TOGGLE_TERRAIN_VISIBILITY:
        m_cTerrain.SetActive(!m_cTerrain.IsActive( )); m_bCameraChanged = true;
        break;
    case TOGGLE_TEXTURING:
        // set for forest
        SForestRenderInfo sForestRenderInfo = m_cForest.GetRenderInfo( );
        sForestRenderInfo.m_bTexturingEnabled = !sForestRenderInfo.m_bTexturingEnabled;
        m_cForest.SetRenderInfo(sForestRenderInfo);
        // set for terrain
        STerrainRenderInfo sTerrainRenderInfo = m_cTerrain.GetRenderInfo( );
        sTerrainRenderInfo.m_bTexturingEnabled = !sTerrainRenderInfo.m_bTexturingEnabled;
        m_cTerrain.SetRenderInfo(sTerrainRenderInfo);
        break;
    }
}
